// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

import "./utils/SoladyTest.sol";
import {MockImplementation} from "./utils/mocks/MockImplementation.sol";
import {ERC1967Factory} from "../src/utils/ERC1967Factory.sol";
import {ERC1967FactoryConstants} from "../src/utils/ERC1967FactoryConstants.sol";

contract ERC1967FactoryTest is SoladyTest {
    event AdminChanged(address indexed proxy, address indexed admin);

    event Upgraded(address indexed proxy, address indexed implementation);

    event Deployed(address indexed proxy, address indexed implementation, address indexed admin);

    ERC1967Factory factory;
    address implementation0;
    address implementation1;

    struct _TestTemps {
        uint256 key;
        uint256 value;
        uint256 msgValue;
        bytes32 salt;
        address predictedProxy;
        address proxy;
    }

    function _testTemps() internal returns (_TestTemps memory t) {
        t.key = _random();
        t.value = _random();
        t.msgValue = _bound(_random(), 0, uint256(type(uint96).max));
        t.salt = bytes32(_random() & uint256(type(uint96).max));
    }

    function setUp() public {
        factory = new ERC1967Factory();
        implementation0 = address(new MockImplementation());
        implementation1 = address(new MockImplementation());
    }

    modifier withFactories() {
        _;
        {
            address minedFactoryAddress = 0x0000000000001122334455667788990011223344;
            vm.etch(minedFactoryAddress, address(factory).code);
            factory = ERC1967Factory(minedFactoryAddress);
        }
        _;
    }

    function testDeploy() public withFactories {
        (address admin,) = _randomSigner();

        vm.prank(admin);
        address proxy = factory.deploy(implementation0, admin);
        _checkProxyBytecode(proxy);

        assertEq(factory.adminOf(proxy), admin);
        assertTrue(proxy != address(0));
        assertTrue(proxy.code.length > 0);
        _checkImplementationSlot(proxy, implementation0);
    }

    function testDeployBrutalized(uint256) public withFactories {
        (address admin,) = _randomSigner();
        admin = _cleaned(admin);
        address implementation = implementation0;
        bool brutalized;
        bool success;
        address f = address(factory);
        /// @solidity memory-safe-assembly
        assembly {
            calldatacopy(0x00, 0x00, 0x40)
            brutalized := eq(and(mload(0x00), 1), 0)
            if brutalized {
                // Extremely unlikely that all 96 upper bits will be zero.
                admin := or(shl(160, keccak256(0x00, 0x20)), admin)
                implementation := or(shl(160, keccak256(0x00, 0x40)), implementation)
            }
            let m := mload(0x40)
            mstore(m, 0x545e7c61) // `deploy(address, address)`.
            mstore(add(m, 0x20), implementation)
            mstore(add(m, 0x40), admin)
            mstore(0x00, 0)
            // Basically, we want to demonstrate that Solidity has checks
            // to reject dirty upper bits for addresses.
            success := call(gas(), f, 0, add(m, 0x1c), 0x44, 0x00, 0x20)
            // If the call is successful, there will be a deployment.
            if and(success, iszero(mload(0x00))) { revert(0, 0) }
        }
        assertEq(brutalized, !success);
    }

    function testDeployAndCall(uint256) public withFactories {
        (address admin,) = _randomSigner();
        _TestTemps memory t = _testTemps();

        bytes memory data = abi.encodeWithSignature("setValue(uint256,uint256)", t.key, t.value);
        vm.deal(admin, type(uint128).max);
        vm.prank(admin);
        address proxy = factory.deployAndCall{value: t.msgValue}(implementation0, admin, data);

        assertEq(factory.adminOf(proxy), admin);
        assertTrue(proxy != address(0));
        assertTrue(proxy.code.length > 0);
        _checkImplementationSlot(proxy, implementation0);
        assertEq(MockImplementation(proxy).getValue(t.key), t.value);
        assertEq(proxy.balance, t.msgValue);
    }

    function testDeployDeterministicAndCall(uint256) public withFactories {
        (address admin,) = _randomSigner();
        _TestTemps memory t = _testTemps();

        t.predictedProxy = factory.predictDeterministicAddress(t.salt);
        bytes memory data = abi.encodeWithSignature("setValue(uint256,uint256)", t.key, t.value);
        vm.deal(admin, type(uint128).max);
        vm.prank(admin);
        if (_randomChance(8)) {
            t.salt = keccak256(abi.encode(_random()));
            vm.expectRevert(ERC1967Factory.SaltDoesNotStartWithCaller.selector);
            t.proxy = factory.deployDeterministicAndCall{value: t.msgValue}(
                implementation0, admin, t.salt, data
            );
            return;
        } else {
            vm.expectEmit(true, true, true, true);
            emit Deployed(t.predictedProxy, implementation0, _cleaned(admin));
            t.proxy = factory.deployDeterministicAndCall{value: t.msgValue}(
                implementation0, admin, t.salt, data
            );
            assertEq(t.proxy, t.predictedProxy);
        }

        assertEq(factory.adminOf(t.proxy), admin);
        assertTrue(t.proxy != address(0));
        assertTrue(t.proxy.code.length > 0);
        _checkImplementationSlot(t.proxy, implementation0);
        assertEq(MockImplementation(t.proxy).getValue(t.key), t.value);
        assertEq(t.proxy.balance, t.msgValue);
    }

    function testDeployAndCallWithRevert() public withFactories {
        (address admin,) = _randomSigner();

        bytes memory data = abi.encodeWithSignature("fails()");
        vm.expectRevert(MockImplementation.Fail.selector);
        factory.deployAndCall(implementation0, admin, data);
    }

    function testProxySucceeds() public withFactories {
        (address admin,) = _randomSigner();
        uint256 a = 1;

        MockImplementation proxy = MockImplementation(factory.deploy(implementation0, admin));

        assertEq(proxy.succeeds(a), a);
    }

    function testProxyFails() public withFactories {
        (address admin,) = _randomSigner();

        address proxy = factory.deploy(implementation0, admin);

        vm.expectRevert(MockImplementation.Fail.selector);
        MockImplementation(proxy).fails();
    }

    function testChangeAdmin() public withFactories {
        (address admin, address newAdmin) = _randomAccounts();

        vm.prank(admin);
        address proxy = factory.deploy(implementation0, admin);

        vm.expectEmit(true, true, true, true, address(factory));
        emit AdminChanged(proxy, _cleaned(newAdmin));

        vm.prank(admin);
        factory.changeAdmin(proxy, newAdmin);

        assertEq(factory.adminOf(proxy), newAdmin);
    }

    function testChangeAdminUnauthorized() public withFactories {
        (address admin, address sussyAccount) = _randomAccounts();

        vm.prank(admin);
        address proxy = factory.deploy(implementation0, admin);

        vm.expectRevert(ERC1967Factory.Unauthorized.selector);

        vm.prank(sussyAccount);
        factory.changeAdmin(proxy, sussyAccount);
    }

    function testUpgrade() public withFactories {
        (address admin,) = _randomSigner();

        vm.prank(admin);
        address proxy = factory.deploy(implementation0, admin);

        vm.expectEmit(true, true, true, true, address(factory));
        emit Upgraded(proxy, implementation1);

        vm.prank(admin);
        factory.upgrade(proxy, implementation1);

        _checkImplementationSlot(proxy, implementation1);
    }

    function testUpgradeAndCall() public withFactories {
        (address admin,) = _randomSigner();
        _TestTemps memory t = _testTemps();

        vm.prank(admin);
        address proxy = factory.deploy(implementation0, admin);

        vm.expectEmit(true, true, true, true, address(factory));
        emit Upgraded(proxy, implementation1);

        vm.prank(admin);
        vm.deal(admin, type(uint128).max);
        bytes memory data = abi.encodeWithSignature("setValue(uint256,uint256)", t.key, t.value);
        factory.upgradeAndCall{value: t.msgValue}(proxy, implementation1, data);

        _checkImplementationSlot(proxy, implementation1);
        uint256 gasBefore = gasleft();
        uint256 storedValue = MockImplementation(proxy).getValue(t.key);
        unchecked {
            uint256 gasUsed = gasBefore - gasleft();
            emit LogUint("gasUsed", gasUsed);
        }
        assertEq(storedValue, t.value);
        assertEq(proxy.balance, t.msgValue);
    }

    function testUpgradeAndCallWithRevert() public withFactories {
        (address admin,) = _randomSigner();

        vm.prank(admin);
        address proxy = factory.deploy(implementation0, admin);

        vm.prank(admin);
        vm.expectRevert(MockImplementation.Fail.selector);
        factory.upgradeAndCall(proxy, implementation1, abi.encodeWithSignature("fails()"));
    }

    function testUpgradeUnauthorized() public withFactories {
        (address admin, address sussyAccount) = _randomAccounts();

        vm.prank(admin);
        address proxy = factory.deploy(implementation0, admin);

        vm.expectRevert(ERC1967Factory.Unauthorized.selector);
        vm.prank(sussyAccount);
        factory.upgrade(proxy, implementation1);

        vm.expectRevert(ERC1967Factory.Unauthorized.selector);
        vm.prank(address(uint160(admin) ^ 1));
        factory.upgrade(proxy, implementation1);

        vm.prank(admin);
        factory.upgrade(proxy, implementation1);
    }

    function testUpgradeWithCorruptedProxy() public withFactories {
        (address admin,) = _randomSigner();

        vm.prank(admin);
        address proxy = factory.deploy(implementation0, admin);

        vm.expectRevert(ERC1967Factory.Unauthorized.selector);
        vm.prank(admin);
        factory.upgrade(address(uint160(proxy) ^ 1), implementation1);

        _checkImplementationSlot(proxy, implementation0);
    }

    function testFactoryDeployment() public {
        address deployment =
            _safeCreate2(ERC1967FactoryConstants.SALT, ERC1967FactoryConstants.INITCODE);
        assertEq(deployment, ERC1967FactoryConstants.ADDRESS);
        assertEq(deployment.code, ERC1967FactoryConstants.BYTECODE);
    }

    function _randomAccounts() internal returns (address a, address b) {
        (a,) = _randomSigner();
        do {
            (b,) = _randomSigner();
        } while (a == b);
    }

    function _checkImplementationSlot(address proxy, address implementation) internal {
        bytes32 slot = bytes32(uint256(keccak256("eip1967.proxy.implementation")) - 1);
        assertEq(vm.load(proxy, slot), bytes32(uint256(uint160(implementation))));
    }

    function _checkProxyBytecode(address proxy) internal {
        bytes memory code = address(proxy).code;
        assertEq(uint8(bytes1(code[code.length - 1])), 0xfd);
        assertTrue(code.length == 127 || code.length == 121);
    }
}

test/ERC20.t.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

import "./utils/SoladyTest.sol";
import "./utils/InvariantTest.sol";

import {ERC20, MockERC20} from "./utils/mocks/MockERC20.sol";
import {MockERC20ForPermit2} from "./utils/mocks/MockERC20ForPermit2.sol";

contract ERC20ForPermit2Test is SoladyTest {
    MockERC20ForPermit2 token;

    address internal constant _PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;

    function setUp() public {
        token = new MockERC20ForPermit2("Token", "TKN", 18);
    }

    function testApproveToPermit2(address owner, uint256 amount) public {
        vm.prank(owner);
        if (amount != type(uint256).max) {
            vm.expectRevert(ERC20.Permit2AllowanceIsFixedAtInfinity.selector);
        }
        token.approve(_PERMIT2, amount);
    }

    function testPermitToPermit2(address owner, uint256 amount) public {
        vm.prank(owner);
        if (amount != type(uint256).max) {
            vm.expectRevert(ERC20.Permit2AllowanceIsFixedAtInfinity.selector);
        } else {
            vm.expectRevert(ERC20.InvalidPermit.selector);
        }
        token.permit(owner, _PERMIT2, amount, block.timestamp, 0, bytes32(0), bytes32(0));
    }

    function testTransferFrom(address owner, uint256 amount) public {
        assertEq(token.allowance(owner, _PERMIT2), type(uint256).max);
        token.mint(owner, amount);
        uint256 amountToTransfer = _bound(_random(), 0, amount);
        address notPermit2 = _randomHashedAddress();
        address recipient = _randomHashedAddress();
        vm.prank(notPermit2);
        if (amountToTransfer != 0) {
            vm.expectRevert(ERC20.InsufficientAllowance.selector);
        }
        token.transferFrom(owner, recipient, amountToTransfer);

        vm.prank(_PERMIT2);
        token.transferFrom(owner, recipient, amountToTransfer);
        if (recipient != owner) {
            assertEq(token.balanceOf(recipient), amountToTransfer);
            assertEq(token.balanceOf(owner), amount - amountToTransfer);
        } else {
            assertEq(token.balanceOf(owner), amount);
        }
        assertEq(token.allowance(owner, _PERMIT2), type(uint256).max);
    }

    function check_IsNotUint256MaxTrickEquivalence(uint256 x) public pure {
        bool expected;
        bool optimized;
        /// @solidity memory-safe-assembly
        assembly {
            if add(x, 1) { expected := 1 }
            if not(x) { optimized := 1 }
        }
        assert(optimized == expected);
        expected = x != type(uint256).max;
        assert(optimized == expected);
    }

    function check_IsPermit2AndValueIsNotInfinityTrickEquivalence(address spender, uint256 amount)
        public
        pure
    {
        bool expected = spender == _PERMIT2 && amount != type(uint256).max;
        bool optimized;
        /// @solidity memory-safe-assembly
        assembly {
            if iszero(or(xor(shr(96, shl(96, spender)), _PERMIT2), iszero(not(amount)))) {
                optimized := 1
            }
        }
        assert(optimized == expected);
    }
}

contract ERC20Test is SoladyTest {
    MockERC20 token;

    address internal constant _PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;

    bytes32 constant PERMIT_TYPEHASH = keccak256(
        "Permit(address owner,address spender,uint256 value,uint256 nonce,uint256 deadline)"
    );

    event Transfer(address indexed from, address indexed to, uint256 amount);

    event Approval(address indexed owner, address indexed spender, uint256 amount);

    struct _TestTemps {
        address owner;
        address to;
        uint256 amount;
        uint256 deadline;
        uint8 v;
        bytes32 r;
        bytes32 s;
        uint256 privateKey;
        uint256 nonce;
    }

    function _testTemps() internal returns (_TestTemps memory t) {
        (t.owner, t.privateKey) = _randomSigner();
        t.to = _randomNonZeroAddress();
        t.amount = _random();
        t.deadline = _random();
    }

    function setUp() public {
        token = new MockERC20("Token", "TKN", 18);
    }

    function testMetadata() public {
        assertEq(token.name(), "Token");
        assertEq(token.symbol(), "TKN");
        assertEq(token.decimals(), 18);
    }

    function testMint() public {
        vm.expectEmit(true, true, true, true);
        emit Transfer(address(0), address(0xBEEF), 1e18);
        token.mint(address(0xBEEF), 1e18);

        assertEq(token.totalSupply(), 1e18);
        assertEq(token.balanceOf(address(0xBEEF)), 1e18);
    }

    function testBurn() public {
        token.mint(address(0xBEEF), 1e18);

        vm.expectEmit(true, true, true, true);
        emit Transfer(address(0xBEEF), address(0), 0.9e18);
        token.burn(address(0xBEEF), 0.9e18);

        assertEq(token.totalSupply(), 1e18 - 0.9e18);
        assertEq(token.balanceOf(address(0xBEEF)), 0.1e18);
    }

    function testApprove() public {
        vm.expectEmit(true, true, true, true);
        emit Approval(address(this), address(0xBEEF), 1e18);
        assertTrue(token.approve(address(0xBEEF), 1e18));

        assertEq(token.allowance(address(this), address(0xBEEF)), 1e18);
    }

    function testTransfer() public {
        token.mint(address(this), 1e18);

        vm.expectEmit(true, true, true, true);
        emit Transfer(address(this), address(0xBEEF), 1e18);
        assertTrue(token.transfer(address(0xBEEF), 1e18));
        assertEq(token.totalSupply(), 1e18);

        assertEq(token.balanceOf(address(this)), 0);
        assertEq(token.balanceOf(address(0xBEEF)), 1e18);
    }

    function testTransferFrom() public {
        address from = address(0xABCD);

        token.mint(from, 1e18);

        vm.prank(from);
        token.approve(address(this), 1e18);

        vm.expectEmit(true, true, true, true);
        emit Transfer(from, address(0xBEEF), 1e18);
        assertTrue(token.transferFrom(from, address(0xBEEF), 1e18));
        assertEq(token.totalSupply(), 1e18);

        assertEq(token.allowance(from, address(this)), 0);

        assertEq(token.balanceOf(from), 0);
        assertEq(token.balanceOf(address(0xBEEF)), 1e18);
    }

    function testInfiniteApproveTransferFrom() public {
        address from = address(0xABCD);

        token.mint(from, 1e18);

        vm.prank(from);
        token.approve(address(this), type(uint256).max);

        assertTrue(token.transferFrom(from, address(0xBEEF), 1e18));
        assertEq(token.totalSupply(), 1e18);

        assertEq(token.allowance(from, address(this)), type(uint256).max);

        assertEq(token.balanceOf(from), 0);
        assertEq(token.balanceOf(address(0xBEEF)), 1e18);
    }

    function testPermit() public {
        _TestTemps memory t = _testTemps();
        t.deadline = block.timestamp;

        _signPermit(t);

        _expectPermitEmitApproval(t);
        _permit(t);

        _checkAllowanceAndNonce(t);
    }

    function testMintOverMaxUintReverts() public {
        token.mint(address(this), type(uint256).max);
        vm.expectRevert(ERC20.TotalSupplyOverflow.selector);
        token.mint(address(this), 1);
    }

    function testTransferInsufficientBalanceReverts() public {
        token.mint(address(this), 0.9e18);
        vm.expectRevert(ERC20.InsufficientBalance.selector);
        token.transfer(address(0xBEEF), 1e18);
    }

    function testTransferFromInsufficientAllowanceReverts() public {
        address from = address(0xABCD);

        token.mint(from, 1e18);

        vm.prank(from);
        token.approve(address(this), 0.9e18);

        vm.expectRevert(ERC20.InsufficientAllowance.selector);
        token.transferFrom(from, address(0xBEEF), 1e18);
    }

    function testTransferFromInsufficientBalanceReverts() public {
        address from = address(0xABCD);

        token.mint(from, 0.9e18);

        vm.prank(from);
        token.approve(address(this), 1e18);

        vm.expectRevert(ERC20.InsufficientBalance.selector);
        token.transferFrom(from, address(0xBEEF), 1e18);
    }

    function testMint(address to, uint256 amount) public {
        vm.expectEmit(true, true, true, true);
        emit Transfer(address(0), to, amount);
        token.mint(to, amount);

        assertEq(token.totalSupply(), amount);
        assertEq(token.balanceOf(to), amount);
    }

    function testBurn(address from, uint256 mintAmount, uint256 burnAmount) public {
        burnAmount = _bound(burnAmount, 0, mintAmount);

        token.mint(from, mintAmount);
        vm.expectEmit(true, true, true, true);
        emit Transfer(from, address(0), burnAmount);
        token.burn(from, burnAmount);

        assertEq(token.totalSupply(), mintAmount - burnAmount);
        assertEq(token.balanceOf(from), mintAmount - burnAmount);
    }

    function testApprove(address to, uint256 amount) public {
        if (to == _PERMIT2) {
            amount = type(uint256).max;
        }
        assertTrue(token.approve(to, amount));
        assertEq(token.allowance(address(this), to), amount);
    }

    function testTransfer(address to, uint256 amount) public {
        token.mint(address(this), amount);

        vm.expectEmit(true, true, true, true);
        emit Transfer(address(this), to, amount);
        assertTrue(token.transfer(to, amount));
        assertEq(token.totalSupply(), amount);

        if (address(this) == to) {
            assertEq(token.balanceOf(address(this)), amount);
        } else {
            assertEq(token.balanceOf(address(this)), 0);
            assertEq(token.balanceOf(to), amount);
        }
    }

    function testTransferFrom(
        address spender,
        address from,
        address to,
        uint256 approval,
        uint256 amount
    ) public {
        vm.assume(spender != _PERMIT2);
        amount = _bound(amount, 0, approval);

        token.mint(from, amount);
        assertEq(token.balanceOf(from), amount);

        vm.prank(from);
        token.approve(spender, approval);

        vm.expectEmit(true, true, true, true);
        emit Transfer(from, to, amount);
        vm.prank(spender);
        assertTrue(token.transferFrom(from, to, amount));
        assertEq(token.totalSupply(), amount);

        if (approval == type(uint256).max) {
            assertEq(token.allowance(from, spender), approval);
        } else {
            assertEq(token.allowance(from, spender), approval - amount);
        }

        if (from == to) {
            assertEq(token.balanceOf(from), amount);
        } else {
            assertEq(token.balanceOf(from), 0);
            assertEq(token.balanceOf(to), amount);
        }
    }

    function testDirectTransfer(uint256) public {
        _TestTemps memory t = _testTemps();
        while (t.owner == t.to) (t.to,) = _randomSigner();

        uint256 totalSupply = _random();
        token.mint(t.owner, totalSupply);
        assertEq(token.balanceOf(t.owner), totalSupply);
        assertEq(token.balanceOf(t.to), 0);
        if (t.amount > totalSupply) {
            vm.expectRevert(ERC20.InsufficientBalance.selector);
            token.directTransfer(t.owner, t.to, t.amount);
        } else {
            vm.expectEmit(true, true, true, true);
            emit Transfer(t.owner, t.to, t.amount);
            token.directTransfer(t.owner, t.to, t.amount);
            assertEq(token.balanceOf(t.owner), totalSupply - t.amount);
            assertEq(token.balanceOf(t.to), t.amount);
        }
    }

    function testDirectSpendAllowance(uint256) public {
        _TestTemps memory t = _testTemps();
        uint256 allowance = _random();
        vm.prank(t.owner);
        token.approve(t.to, allowance);
        assertEq(token.allowance(t.owner, t.to), allowance);
        if (allowance == type(uint256).max) {
            token.directSpendAllowance(t.owner, t.to, t.amount);
            assertEq(token.allowance(t.owner, t.to), allowance);
        } else if (t.amount > allowance) {
            vm.expectRevert(ERC20.InsufficientAllowance.selector);
            token.directSpendAllowance(t.owner, t.to, t.amount);
        } else {
            token.directSpendAllowance(t.owner, t.to, t.amount);
            assertEq(token.allowance(t.owner, t.to), allowance - t.amount);
        }
    }

    function testPermit(uint256) public {
        _TestTemps memory t = _testTemps();
        if (t.deadline < block.timestamp) t.deadline = block.timestamp;

        _signPermit(t);

        _expectPermitEmitApproval(t);
        _permit(t);

        _checkAllowanceAndNonce(t);
    }

    function _checkAllowanceAndNonce(_TestTemps memory t) internal {
        assertEq(token.allowance(t.owner, t.to), t.amount);
        assertEq(token.nonces(t.owner), t.nonce + 1);
    }

    function testBurnInsufficientBalanceReverts(address to, uint256 mintAmount, uint256 burnAmount)
        public
    {
        if (mintAmount == type(uint256).max) mintAmount--;
        burnAmount = _bound(burnAmount, mintAmount + 1, type(uint256).max);

        token.mint(to, mintAmount);
        vm.expectRevert(ERC20.InsufficientBalance.selector);
        token.burn(to, burnAmount);
    }

    function testTransferInsufficientBalanceReverts(
        address to,
        uint256 mintAmount,
        uint256 sendAmount
    ) public {
        if (mintAmount == type(uint256).max) mintAmount--;
        sendAmount = _bound(sendAmount, mintAmount + 1, type(uint256).max);

        token.mint(address(this), mintAmount);
        vm.expectRevert(ERC20.InsufficientBalance.selector);
        token.transfer(to, sendAmount);
    }

    function testTransferFromInsufficientAllowanceReverts(
        address to,
        uint256 approval,
        uint256 amount
    ) public {
        if (approval == type(uint256).max) approval--;
        amount = _bound(amount, approval + 1, type(uint256).max);

        address from = address(0xABCD);

        token.mint(from, amount);

        vm.prank(from);
        token.approve(address(this), approval);

        vm.expectRevert(ERC20.InsufficientAllowance.selector);
        token.transferFrom(from, to, amount);
    }

    function testTransferFromInsufficientBalanceReverts(
        address to,
        uint256 mintAmount,
        uint256 sendAmount
    ) public {
        if (mintAmount == type(uint256).max) mintAmount--;
        sendAmount = _bound(sendAmount, mintAmount + 1, type(uint256).max);

        address from = address(0xABCD);

        token.mint(from, mintAmount);

        vm.prank(from);
        token.approve(address(this), sendAmount);

        vm.expectRevert(ERC20.InsufficientBalance.selector);
        token.transferFrom(from, to, sendAmount);
    }

    function testPermitBadNonceReverts(uint256) public {
        _TestTemps memory t = _testTemps();
        if (t.deadline < block.timestamp) t.deadline = block.timestamp;
        while (t.nonce == 0) t.nonce = _random();

        _signPermit(t);

        vm.expectRevert(ERC20.InvalidPermit.selector);
        _permit(t);
    }

    function testPermitBadDeadlineReverts(uint256) public {
        _TestTemps memory t = _testTemps();
        if (t.deadline == type(uint256).max) t.deadline--;
        if (t.deadline < block.timestamp) t.deadline = block.timestamp;

        _signPermit(t);

        vm.expectRevert(ERC20.InvalidPermit.selector);
        t.deadline += 1;
        _permit(t);
    }

    function testPermitPastDeadlineReverts(uint256) public {
        _TestTemps memory t = _testTemps();
        t.deadline = _bound(t.deadline, 0, block.timestamp - 1);

        _signPermit(t);

        vm.expectRevert(ERC20.PermitExpired.selector);
        _permit(t);
    }

    function testPermitReplayReverts(uint256) public {
        _TestTemps memory t = _testTemps();
        if (t.deadline < block.timestamp) t.deadline = block.timestamp;

        _signPermit(t);

        _expectPermitEmitApproval(t);
        _permit(t);
        vm.expectRevert(ERC20.InvalidPermit.selector);
        _permit(t);
    }

    function _signPermit(_TestTemps memory t) internal view {
        bytes32 innerHash =
            keccak256(abi.encode(PERMIT_TYPEHASH, t.owner, t.to, t.amount, t.nonce, t.deadline));
        bytes32 domainSeparator = token.DOMAIN_SEPARATOR();
        bytes32 outerHash = keccak256(abi.encodePacked("\x19\x01", domainSeparator, innerHash));
        (t.v, t.r, t.s) = vm.sign(t.privateKey, outerHash);
    }

    function _expectPermitEmitApproval(_TestTemps memory t) internal {
        vm.expectEmit(true, true, true, true);
        emit Approval(t.owner, t.to, t.amount);
    }

    function _permit(_TestTemps memory t) internal {
        address token_ = address(token);
        /// @solidity memory-safe-assembly
        assembly {
            let m := mload(sub(t, 0x20))
            mstore(sub(t, 0x20), 0xd505accf)
            let success := call(gas(), token_, 0, sub(t, 0x04), 0xe4, 0x00, 0x00)
            if iszero(success) {
                returndatacopy(0, 0, returndatasize())
                revert(0, returndatasize())
            }
            mstore(sub(t, 0x20), m)
        }
    }
}

contract ERC20Invariants is SoladyTest, InvariantTest {
    BalanceSum balanceSum;
    MockERC20 token;

    function setUp() public {
        token = new MockERC20("Token", "TKN", 18);
        balanceSum = new BalanceSum(token);
        _addTargetContract(address(balanceSum));
    }

    function invariantBalanceSum() public {
        assertEq(token.totalSupply(), balanceSum.sum());
    }
}

contract BalanceSum {
    MockERC20 token;
    uint256 public sum;

    constructor(MockERC20 _token) {
        token = _token;
    }

    function mint(address from, uint256 amount) public {
        token.mint(from, amount);
        sum += amount;
    }

    function burn(address from, uint256 amount) public {
        token.burn(from, amount);
        sum -= amount;
    }

    function approve(address to, uint256 amount) public {
        token.approve(to, amount);
    }

    function transferFrom(address from, address to, uint256 amount) public {
        token.transferFrom(from, to, amount);
    }

    function transfer(address to, uint256 amount) public {
        token.transfer(to, amount);
    }
}

test/ERC20Votes.t.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

import "./utils/SoladyTest.sol";
import {ERC20, ERC20Votes, MockERC20Votes} from "./utils/mocks/MockERC20Votes.sol";
import {FixedPointMathLib} from "../src/utils/FixedPointMathLib.sol";

contract ERC20VotesTest is SoladyTest {
    MockERC20Votes erc20Votes;

    event DelegateChanged(address indexed delegator, address indexed from, address indexed to);
    event DelegateVotesChanged(address indexed delegate, uint256 oldValue, uint256 newValue);

    address internal constant _ALICE = address(111);
    address internal constant _BOB = address(222);
    address internal constant _CHARLIE = address(333);
    address internal constant _DAVID = address(444);

    function setUp() public {
        erc20Votes = new MockERC20Votes();
    }

    function testSetAndGetDelegate(address delegator, address delegatee) public {
        erc20Votes.directDelegate(delegator, delegatee);
        assertEq(erc20Votes.delegates(delegator), delegatee);
    }

    function testMintTransferBurnDelegate() public {
        uint256 initialBlockNumber = vm.getBlockNumber();
        erc20Votes.mint(_ALICE, 1 ether);

        // Minting does not automatically give one votes.
        assertEq(erc20Votes.getVotes(_ALICE), 0);
        assertEq(erc20Votes.getVotes(_BOB), 0);
        assertEq(erc20Votes.getVotesTotalSupply(), 1 ether);

        vm.expectEmit(true, true, true, true);
        emit DelegateChanged(_ALICE, address(0), _BOB);
        vm.prank(_ALICE);
        erc20Votes.delegate(_BOB);

        assertEq(erc20Votes.getVotes(_BOB), 1 ether);
        assertEq(erc20Votes.getVotes(_DAVID), 0 ether);

        vm.expectEmit(true, true, true, true);
        emit DelegateChanged(_CHARLIE, address(0), _DAVID);
        vm.prank(_CHARLIE);
        erc20Votes.delegate(_DAVID);

        vm.prank(_ALICE);
        erc20Votes.transfer(_CHARLIE, 0.3 ether);

        assertEq(erc20Votes.getVotes(_BOB), 0.7 ether);
        assertEq(erc20Votes.getVotes(_DAVID), 0.3 ether);

        vm.roll(initialBlockNumber + 1);

        erc20Votes.burn(_ALICE, 0.1 ether);
        assertEq(erc20Votes.getVotes(_BOB), 0.6 ether);
        assertEq(erc20Votes.getVotes(_DAVID), 0.3 ether);

        vm.roll(initialBlockNumber + 2);

        vm.expectEmit(true, true, true, true);
        emit DelegateChanged(_CHARLIE, _DAVID, _BOB);
        vm.expectEmit(true, true, true, true);
        emit DelegateVotesChanged(_DAVID, 0.3 ether, 0 ether);
        vm.expectEmit(true, true, true, true);
        emit DelegateVotesChanged(_BOB, 0.6 ether, 0.9 ether);
        vm.prank(_CHARLIE);
        erc20Votes.delegate(_BOB);

        vm.roll(initialBlockNumber + 3);

        assertEq(erc20Votes.getVotes(_BOB), 0.9 ether);
        assertEq(erc20Votes.getPastVotes(_BOB, initialBlockNumber + 0), 0.7 ether);
        assertEq(erc20Votes.getPastVotes(_BOB, initialBlockNumber + 1), 0.6 ether);
        _checkCheckpointAt(_BOB, 0, initialBlockNumber + 0, 0.7 ether);
        _checkCheckpointAt(_BOB, 1, initialBlockNumber + 1, 0.6 ether);
        assertEq(erc20Votes.getVotes(_DAVID), 0 ether);
        assertEq(erc20Votes.getPastVotes(_DAVID, initialBlockNumber + 0), 0.3 ether);
        assertEq(erc20Votes.getPastVotes(_DAVID, initialBlockNumber + 1), 0.3 ether);
        _checkCheckpointAt(_DAVID, 0, initialBlockNumber + 0, 0.3 ether);
        _checkCheckpointAt(_DAVID, 1, initialBlockNumber + 2, 0 ether);

        assertEq(erc20Votes.getVotesTotalSupply(), 0.9 ether);
        assertEq(erc20Votes.getPastVotesTotalSupply(initialBlockNumber + 0), 1 ether);
        assertEq(erc20Votes.getPastVotesTotalSupply(initialBlockNumber + 1), 0.9 ether);

        uint256 currentBlockNumber = vm.getBlockNumber();
        vm.expectRevert(ERC20Votes.ERC5805FutureLookup.selector);
        erc20Votes.getPastVotesTotalSupply(currentBlockNumber);
    }

    function _checkCheckpointAt(
        address account,
        uint256 i,
        uint256 expectedClock,
        uint256 expectedValue
    ) internal {
        (uint48 checkpointClock, uint256 checkpointValue) = erc20Votes.checkpointAt(account, i);
        assertEq(checkpointClock, expectedClock);
        assertEq(checkpointValue, expectedValue);
    }

    function _advanceBlockNumber() internal {
        vm.roll(vm.getBlockNumber() + (_randomUniform() & 3));
    }

    struct _TestVoteInvariantsTemps {
        address[] accounts;
        address[] delegates;
    }

    function testVoteInvariants(bytes32) public {
        vm.pauseGasMetering();
        unchecked {
            _TestVoteInvariantsTemps memory t;
            t.accounts = new address[](1 + (_randomUniform() & 3));
            t.delegates = new address[](t.accounts.length + 1);
            for (uint256 i; i != t.accounts.length; ++i) {
                address account = _randomUniqueHashedAddress();
                t.accounts[i] = account;
                t.delegates[i + 1] = account;
                if (!_randomChance(4)) {
                    erc20Votes.mint(account, _bound(_random(), 0, 2 ** 161 - 1));
                }
            }
            do {
                if (_randomChance(2)) {
                    address delegator = t.accounts[_randomUniform() % t.accounts.length];
                    address delegate = t.delegates[_randomUniform() % t.delegates.length];
                    vm.prank(delegator);
                    erc20Votes.delegate(delegate);
                    if (erc20Votes.balanceOf(delegator) != 0 && delegate != address(0)) {
                        assertGt(erc20Votes.getVotes(delegate), 0);
                    }
                }
                if (_randomChance(4)) _advanceBlockNumber();
                if (_randomChance(2)) {
                    address from = t.accounts[_randomUniform() % t.accounts.length];
                    address to = t.accounts[_randomUniform() % t.accounts.length];
                    uint256 amount = _bound(_random(), 0, erc20Votes.balanceOf(from));
                    vm.prank(from);
                    erc20Votes.transfer(to, amount);
                }
                if (_randomChance(4)) _advanceBlockNumber();
                if (_randomChance(4)) {
                    address account = t.accounts[_randomUniform() % t.accounts.length];
                    uint256 amount = _bound(_random(), 0, erc20Votes.balanceOf(account));
                    erc20Votes.burn(account, amount);
                }
                if (_randomChance(4)) _advanceBlockNumber();
                if (_randomChance(4)) {
                    address account = t.accounts[_randomUniform() % t.accounts.length];
                    uint256 amount = _bound(_random(), 0, 2 ** 161 - 1);
                    erc20Votes.mint(account, amount);
                }
                if (_randomChance(4)) _advanceBlockNumber();
                if (_randomChance(8)) _checkVoteInvariants(t);
            } while (!_randomChance(4));
            _checkVoteInvariants(t);
        }
        vm.resumeGasMetering();
    }

    function _checkVoteInvariants(_TestVoteInvariantsTemps memory t) internal {
        unchecked {
            uint256 totalVotes = 0;
            for (uint256 j; j != t.delegates.length; ++j) {
                totalVotes += erc20Votes.getVotes(t.delegates[j]);
            }
            for (uint256 j; j != t.delegates.length; ++j) {
                uint256 totalBalanceForDelegate = 0;
                for (uint256 i; i != t.accounts.length; ++i) {
                    if (erc20Votes.delegates(t.accounts[i]) == t.delegates[j]) {
                        totalBalanceForDelegate += erc20Votes.balanceOf(t.accounts[i]);
                    }
                }
                assertLe(erc20Votes.getVotes(t.delegates[j]), totalBalanceForDelegate);
            }
            assertLe(totalVotes, erc20Votes.getVotesTotalSupply());
            assertEq(erc20Votes.getVotesTotalSupply(), erc20Votes.totalSupply());
        }
        unchecked {
            for (uint256 j; j != t.delegates.length; ++j) {
                uint256 checkpointCount = erc20Votes.checkpointCount(t.delegates[j]);
                if (_randomChance(2) && checkpointCount != 0) {
                    uint256 i = _bound(_random(), 0, checkpointCount - 1);
                    erc20Votes.checkpointAt(t.delegates[j], i);
                } else if (checkpointCount != 0) {
                    uint256 i = _bound(_random(), checkpointCount, checkpointCount + 10);
                    vm.expectRevert(ERC20Votes.ERC5805CheckpointIndexOutOfBounds.selector);
                    erc20Votes.checkpointAt(t.delegates[j], i);
                }
            }
        }
    }

    function testClockTrick(uint48 x) public pure {
        /// @solidity memory-safe-assembly
        assembly {
            returndatacopy(returndatasize(), returndatasize(), sub(0, shr(48, x)))
        }
    }

    struct _TestDelegateBySigTemps {
        address signer;
        uint256 privateKey;
        uint256 nonce;
        uint256 expiry;
        address delegatee;
        uint8 v;
        bytes32 r;
        bytes32 s;
    }

    bytes32 internal constant _ERC5805_DELEGATION_TYPEHASH =
        keccak256("Delegation(address delegatee,uint256 nonce,uint256 expiry)");

    function _signDelegate(_TestDelegateBySigTemps memory t) internal view {
        bytes32 innerHash =
            keccak256(abi.encode(_ERC5805_DELEGATION_TYPEHASH, t.delegatee, t.nonce, t.expiry));
        bytes32 domainSeparator = keccak256(
            abi.encode(
                keccak256(
                    "EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"
                ),
                keccak256(bytes(erc20Votes.name())),
                keccak256("1"),
                block.chainid,
                address(erc20Votes)
            )
        );
        bytes32 outerHash = keccak256(abi.encodePacked("\x19\x01", domainSeparator, innerHash));
        (t.v, t.r, t.s) = vm.sign(t.privateKey, outerHash);
    }

    function _delegateBySig(_TestDelegateBySigTemps memory t) internal {
        bytes memory data = abi.encodeWithSignature(
            "delegateBySig(address,uint256,uint256,uint8,bytes32,bytes32)",
            t.delegatee,
            t.nonce,
            t.expiry,
            t.v,
            t.r,
            t.s
        );
        (bool success,) = address(erc20Votes).call(data);
        assert(success);
    }

    function testDelegateBySig(bytes32) public {
        _TestDelegateBySigTemps memory t;
        t.delegatee = _randomHashedAddress();
        (t.signer, t.privateKey) = _randomSigner();
        t.nonce = _randomUniform() & 7;
        t.expiry = _bound(_randomUniform(), 10, 2 ** 32 - 1);
        if (!_randomChance(32)) {
            unchecked {
                for (uint256 i; i != t.nonce; ++i) {
                    erc20Votes.directIncrementNonce(t.signer);
                }
                assertEq(t.nonce, erc20Votes.nonces(t.signer));
            }
        }
        _signDelegate(t);
        uint256 timestamp = _bound(_randomUniform(), 10, 2 ** 32 - 1);
        vm.warp(timestamp);
        if (timestamp > t.expiry) {
            vm.expectRevert(ERC20Votes.ERC5805DelegateSignatureExpired.selector);
            _delegateBySig(t);
        } else if (t.nonce != erc20Votes.nonces(t.signer)) {
            vm.expectRevert(ERC20Votes.ERC5805DelegateInvalidSignature.selector);
            _delegateBySig(t);
        } else {
            _delegateBySig(t);
            assertEq(t.nonce + 1, erc20Votes.nonces(t.signer));
            assertEq(erc20Votes.delegates(t.signer), t.delegatee);
        }
    }

    struct Checkpoint {
        uint256 key;
        uint256 value;
    }

    Checkpoint[] internal _trace;

    function testSmallSqrtApprox(uint32 n) public {
        uint256 approx = _smallSqrtApprox(n);
        uint256 groundTruth = FixedPointMathLib.sqrt(n);
        assertGe(approx, groundTruth);
        assertLe(FixedPointMathLib.dist(approx, groundTruth), 3);
    }

    function _smallSqrtApprox(uint256 n) internal pure returns (uint256 m) {
        /// @solidity memory-safe-assembly
        assembly {
            m := shl(4, lt(0xffff, n))
            m := shl(shr(1, or(shl(3, lt(0xff, shr(m, n))), m)), 16)
            m := shr(1, add(m, div(n, m)))
            m := shr(1, add(m, div(n, m)))
            m := shr(1, add(m, div(n, m)))
            m := shr(1, add(m, div(n, m)))
            m := shr(1, add(m, div(n, m)))
            m := shr(1, add(m, div(n, m)))
        }
    }

    struct _TestCheckpointTemps {
        uint256 key;
        uint256 amount;
        bool isAdd;
        uint256 oldValueOriginal;
        uint256 oldValue;
        uint256 newValueOriginal;
        uint256 newValue;
    }

    function testCheckpointPush(uint256 lengthSlot) public {
        lengthSlot = uint256(keccak256(abi.encode(lengthSlot, "hehe")));
        uint256 key = _randomUniform() & 0xf;
        if (_randomChance(2)) {
            this.checkpointPushDiff(lengthSlot, key, type(uint256).max - 10, true);
            key += _randomUniform() & 0xf;
            uint256 amount = _randomUniform() % 20;
            if (amount <= 10) {
                this.checkpointPushDiff(lengthSlot, key, amount, true);
                assertEq(_checkpointLatest(lengthSlot), type(uint256).max - 10 + amount);
            } else {
                vm.expectRevert(ERC20Votes.ERC5805CheckpointValueOverflow.selector);
                this.checkpointPushDiff(lengthSlot, key, amount, true);
            }
        } else {
            this.checkpointPushDiff(lengthSlot, key, 10, true);
            key += _randomUniform() & 0xf;
            uint256 amount = _randomUniform() % 20;
            if (amount <= 10) {
                this.checkpointPushDiff(lengthSlot, key, amount, false);
                assertEq(_checkpointLatest(lengthSlot), 10 - amount);
            } else {
                vm.expectRevert(ERC20Votes.ERC5805CheckpointValueUnderflow.selector);
                this.checkpointPushDiff(lengthSlot, key, amount, false);
            }
        }
    }

    function testCheckpointDifferential(uint256 lengthSlot, uint256 n) public {
        vm.pauseGasMetering();
        lengthSlot = uint256(keccak256(abi.encode(lengthSlot, "hehe")));

        n = _bound(n, 1, _randomChance(32) ? 70 : 8);
        _TestCheckpointTemps memory t;
        do {
            t.key += _randomUniform() & 0xf;
            t.isAdd = _randomChance(2);
            if (t.isAdd) {
                t.amount = _bound(_random(), 0, type(uint256).max - _checkpointLatestOriginal());
            } else {
                t.amount = _bound(_random(), 0, _checkpointLatestOriginal());
            }

            (t.oldValueOriginal, t.newValueOriginal) =
                _checkpointPushDiffOriginal(t.key, t.amount, t.isAdd);

            (t.oldValue, t.newValue) = _checkpointPushDiff(lengthSlot, t.key, t.amount, t.isAdd);

            assertEq(t.oldValue, t.oldValueOriginal);
            assertEq(t.newValue, t.newValueOriginal);
            assertEq(t.key, _checkpointLatestKeyOriginal());
            assertEq(t.key, _checkpointLatestKey(lengthSlot));
            assertEq(_checkpointLatestOriginal(), _checkpointLatest(lengthSlot));

            if (_randomChance(8)) _checkCheckpoints(lengthSlot);
            if (_randomChance(8)) _checkCheckpointUpperLookupRecent(lengthSlot);
        } while (!_randomChance(n));

        _checkCheckpoints(lengthSlot);
        _checkCheckpointUpperLookupRecent(lengthSlot);
        vm.resumeGasMetering();
    }

    function _checkCheckpoints(uint256 lengthSlot) internal tempMemory {
        unchecked {
            uint256 n = _trace.length;
            for (uint256 i; i != n; ++i) {
                (uint256 key, uint256 value) = _checkpointAt(lengthSlot, i);
                Checkpoint storage c = _trace[i];
                assertEq(key, c.key);
                assertEq(value, c.value);
            }
        }
    }

    function _checkCheckpointUpperLookupRecent(uint256 lengthSlot) internal tempMemory {
        uint256 key = _bound(_randomUniform(), 0, _checkpointLatestKeyOriginal() + 3);
        uint256 expected = _checkpointUpperLookupRecentOriginal(key);
        assertEq(_checkpointUpperLookupRecent(lengthSlot, key), expected);
    }

    function _checkpointUpperLookupRecentOriginal(uint256 key)
        private
        view
        tempMemory
        returns (uint256 result)
    {
        unchecked {
            uint256 n = _trace.length;
            for (uint256 i; i != n; ++i) {
                Checkpoint storage c = _trace[i];
                if (c.key > key) break;
                result = c.value;
            }
        }
    }

    function _checkpointPushDiffOriginal(uint256 key, uint256 amount, bool isAdd)
        private
        tempMemory
        returns (uint256 oldValue, uint256 newValue)
    {
        if (_trace.length == 0) {
            newValue = isAdd ? oldValue + amount : oldValue - amount;
            _trace.push(Checkpoint(key, newValue));
        } else {
            Checkpoint storage last = _trace[_trace.length - 1];
            oldValue = last.value;
            newValue = isAdd ? oldValue + amount : oldValue - amount;
            if (last.key > key) revert("Unordered insertion");
            if (last.key == key) {
                last.value = newValue;
            } else {
                _trace.push(Checkpoint(key, newValue));
            }
        }
    }

    function _checkpointLatestKeyOriginal() private view returns (uint256) {
        return _trace.length == 0 ? 0 : _trace[_trace.length - 1].key;
    }

    function _checkpointLatestOriginal() private view returns (uint256) {
        return _trace.length == 0 ? 0 : _trace[_trace.length - 1].value;
    }

    function _checkpointLatestKey(uint256 lengthSlot) private view returns (uint256 result) {
        /// @solidity memory-safe-assembly
        assembly {
            result := shr(208, shl(160, sload(lengthSlot)))
            if result { result := and(0xffffffffffff, sload(add(sub(result, 1), lengthSlot))) }
        }
    }

    function _checkpointAt(uint256 lengthSlot, uint256 i)
        private
        view
        returns (uint48 checkpointClock, uint256 checkpointValue)
    {
        /// @solidity memory-safe-assembly
        assembly {
            if iszero(lt(i, shr(208, shl(160, sload(lengthSlot))))) {
                mstore(0x00, 0x86df9d10) // `ERC5805CheckpointIndexOutOfBounds()`.
                revert(0x1c, 0x04)
            }
            let checkpointPacked := sload(add(i, lengthSlot))
            checkpointClock := and(0xffffffffffff, checkpointPacked)
            checkpointValue := shr(96, checkpointPacked)
            if eq(checkpointValue, address()) { checkpointValue := sload(not(add(i, lengthSlot))) }
        }
    }

    function checkpointPushDiff(uint256 lengthSlot, uint256 key, uint256 amount, bool isAdd)
        public
        returns (uint256 oldValue, uint256 newValue)
    {
        return _checkpointPushDiff(lengthSlot, key, amount, isAdd);
    }

    /// @dev Pushes a checkpoint.
    function _checkpointPushDiff(uint256 lengthSlot, uint256 key, uint256 amount, bool isAdd)
        private
        returns (uint256 oldValue, uint256 newValue)
    {
        /// @solidity memory-safe-assembly
        assembly {
            let lengthSlotPacked := sload(lengthSlot)
            for { let n := shr(208, shl(160, lengthSlotPacked)) } 1 {} {
                if iszero(n) {
                    if iszero(or(isAdd, iszero(amount))) {
                        mstore(0x00, 0x5915f686) // `ERC5805CheckpointValueUnderflow()`.
                        revert(0x1c, 0x04)
                    }
                    newValue := amount
                    if iszero(or(eq(newValue, address()), shr(160, newValue))) {
                        sstore(lengthSlot, or(or(key, shl(48, 1)), shl(96, newValue)))
                        break
                    }
                    sstore(lengthSlot, or(or(key, shl(48, 1)), shl(96, address())))
                    sstore(not(lengthSlot), newValue)
                    break
                }
                let checkpointSlot := add(sub(n, 1), lengthSlot)
                let lastPacked := sload(checkpointSlot)
                oldValue := shr(96, lastPacked)
                if eq(oldValue, address()) { oldValue := sload(not(checkpointSlot)) }
                for {} 1 {} {
                    if iszero(isAdd) {
                        newValue := sub(oldValue, amount)
                        if iszero(gt(newValue, oldValue)) { break }
                        mstore(0x00, 0x5915f686) // `ERC5805CheckpointValueUnderflow()`.
                        revert(0x1c, 0x04)
                    }
                    newValue := add(oldValue, amount)
                    if iszero(lt(newValue, oldValue)) { break }
                    mstore(0x00, 0x9dbbeb75) // `ERC5805CheckpointValueOverflow()`.
                    revert(0x1c, 0x04)
                }
                let lastKey := and(0xffffffffffff, lastPacked)
                if iszero(eq(lastKey, key)) {
                    n := add(1, n)
                    checkpointSlot := add(1, checkpointSlot)
                    sstore(lengthSlot, add(shl(48, 1), lengthSlotPacked))
                }
                if or(gt(lastKey, key), shr(48, n)) { invalid() }
                if iszero(or(eq(newValue, address()), shr(160, newValue))) {
                    sstore(checkpointSlot, or(or(key, shl(48, n)), shl(96, newValue)))
                    break
                }
                sstore(checkpointSlot, or(or(key, shl(48, n)), shl(96, address())))
                sstore(not(checkpointSlot), newValue)
                break
            }
        }
    }

    /// @dev Returns the latest value in the checkpoints.
    function _checkpointLatest(uint256 lengthSlot) private view returns (uint256 result) {
        /// @solidity memory-safe-assembly
        assembly {
            result := shr(208, shl(160, sload(lengthSlot)))
            if result {
                lengthSlot := add(sub(result, 1), lengthSlot) // Reuse for `checkpointSlot`.
                result := shr(96, sload(lengthSlot))
                if eq(result, address()) { result := sload(not(lengthSlot)) }
            }
        }
    }

    /// @dev Returns the value in the checkpoints with the largest key that is less than `key`.
    function _checkpointUpperLookupRecent(uint256 lengthSlot, uint256 key)
        private
        view
        returns (uint256 result)
    {
        /// @solidity memory-safe-assembly
        assembly {
            let l := 0 // Low.
            let h := shr(208, shl(160, sload(lengthSlot))) // High.
            // Start the binary search nearer to the right to optimize for recent checkpoints.
            for {} iszero(lt(h, 6)) {} {
                let m := shl(4, lt(0xffff, h))
                m := shl(shr(1, or(m, shl(3, lt(0xff, shr(m, h))))), 16)
                m := shr(1, add(m, div(h, m)))
                m := shr(1, add(m, div(h, m)))
                m := shr(1, add(m, div(h, m)))
                m := shr(1, add(m, div(h, m)))
                m := shr(1, add(m, div(h, m)))
                m := sub(h, shr(1, add(m, div(h, m)))) // Approx `h - sqrt(h)`.
                if iszero(lt(key, and(sload(add(m, lengthSlot)), 0xffffffffffff))) {
                    l := add(1, m)
                    break
                }
                h := m
                break
            }
            // Binary search.
            for {} lt(l, h) {} {
                let m := shr(1, add(l, h)) // Won't overflow in practice.
                if iszero(lt(key, and(sload(add(m, lengthSlot)), 0xffffffffffff))) {
                    l := add(1, m)
                    continue
                }
                h := m
            }
            let checkpointSlot := add(sub(h, 1), lengthSlot)
            result := mul(iszero(iszero(h)), shr(96, sload(checkpointSlot)))
            if eq(result, address()) { result := sload(not(checkpointSlot)) }
        }
    }
}

