    function testEnumerableSetDifferential(bytes32) public {
        address[] memory a;
        uint256[] memory s = _makeArray(0);
        while (a.length == 0) {
            a = _sampleUniqueAddresses(_randomUniform() & 0xf);
        }
        do {
            for (uint256 q = _randomUniform() & 7; q != 0; --q) {
                address x = a[_randomUniform() % a.length];
