    }

    function testEnumerableUint8Set() public {
        uint8[] memory ordinals = _flagsToOrdinals(0xff00000000ff);
        unchecked {
            for (uint256 i; i != ordinals.length; ++i) {
                uint8Set.add(ordinals[i]);
            }
            uint8[] memory values = uint8Set.values();
            for (uint256 i; i != ordinals.length; ++i) {
                assertEq(uint8Set.at(i), values[i]);
            }
            assertEq(values.length, 16);
        }
    }

    function testEnumerableUint8Set(uint256 flags, bytes32) public {
        uint8[] memory ordinals = _flagsToOrdinals(flags);
        bytes32 sortedHash = keccak256(abi.encodePacked(ordinals));
        _shuffle(ordinals);
        unchecked {
            for (uint256 i; i != ordinals.length; ++i) {
                assertTrue(uint8Set.add(ordinals[i]));
            }
            if (_randomChance(16)) {
                _shuffle(ordinals);
                for (uint256 i; i != ordinals.length; ++i) {
                    assertFalse(uint8Set.add(ordinals[i]));
                }
            }
            if (_randomChance(16)) {
                for (uint256 i; i != 256; ++i) {
                    assertEq(uint8Set.contains(uint8(i)), flags & (1 << i) != 0);
                }
            }
            uint8[] memory values = uint8Set.values();
            assertEq(keccak256(abi.encodePacked(values)), sortedHash);
            assertEq(values.length, uint8Set.length());
            if (_randomChance(16)) {
                for (uint256 i; i != ordinals.length; ++i) {
                    assertEq(uint8Set.at(i), values[i]);
                }
                vm.expectRevert(EnumerableSetLib.IndexOutOfBounds.selector);
                this.uint8SetAt(_bound(_random(), ordinals.length, type(uint256).max));
            }
            if (_randomChance(16)) {
                _shuffle(ordinals);
                for (uint256 i; i != ordinals.length; ++i) {
                    assertTrue(uint8Set.remove(ordinals[i]));
                    assertFalse(uint8Set.remove(ordinals[i]));
                }
                if (_randomChance(32)) {
                    for (uint256 i; i != 256; ++i) {
                        assertFalse(uint8Set.contains(uint8(i)));
                    }
                }
                assertEq(uint8Set.length(), 0);
            }
        }
    }

    function _shuffle(uint8[] memory a) internal {
        LibPRNG.PRNG memory prng;
        prng.state = _random();
        uint256[] memory casted;
        /// @solidity memory-safe-assembly
        assembly {
            casted := a
        }
        prng.shuffle(casted);
    }

    function _flagsToOrdinals(uint256 flags) internal pure returns (uint8[] memory ordinals) {
        ordinals = new uint8[](256);
        uint256 n;
        unchecked {
            for (uint256 i; i != 256; ++i) {
                if (flags & (1 << i) != 0) ordinals[n++] = uint8(i);
            }
        }
        /// @solidity memory-safe-assembly
        assembly {
            mstore(ordinals, n)
        }
    }

    function uint8SetAt(uint256 i) public view returns (uint8) {
        return uint8Set.at(i);
    }

    function addToAddressSet(address a) public returns (bool) {
        return addressSet.add(a);
    }

    function addressSetContains(address a) public view returns (bool) {
        return addressSet.contains(a);
    }

    function removeFromAddressSet(address a) public returns (bool) {
        return addressSet.remove(a);
    }

    function addressSetAt(uint256 i) public view returns (address) {
        return addressSet.at(i);
    }

    function addToBytes32Set(bytes32 a) public returns (bool) {
        return bytes32Set.add(a);
    }

    function bytes32SetContains(bytes32 a) public view returns (bool) {
        return bytes32Set.contains(a);
    }

    function removeFromBytes32Set(bytes32 a) public returns (bool) {
        return bytes32Set.remove(a);
    }

    function bytes32SetAt(uint256 i) public view returns (bytes32) {
        return bytes32Set.at(i);
    }

    function _toUints(address[] memory a) private pure returns (uint256[] memory result) {
        /// @solidity memory-safe-assembly
        assembly {
            result := a
        }
    }

    function _toUints(int256[] memory a) private pure returns (uint256[] memory result) {
        /// @solidity memory-safe-assembly
        assembly {
            result := a
        }
    }

    function _toUints(bytes32[] memory a) private pure returns (uint256[] memory result) {
        /// @solidity memory-safe-assembly
        assembly {
            result := a
        }
    }

    function _makeArray(uint256 size, uint256 maxCap)
        internal
        pure
        returns (uint256[] memory result)
    {
        /// @solidity memory-safe-assembly
        assembly {
            result := mload(0x40)
            mstore(result, size)
            mstore(0x40, add(result, shl(5, add(maxCap, 1))))
        }
    }

    function _makeArray(uint256 size) internal pure returns (uint256[] memory result) {
        require(size <= 512, "Size too big.");
        result = _makeArray(size, 512);
    }

    function _addToArray(uint256[] memory a, uint256 x) internal pure {
        /// @solidity memory-safe-assembly
        assembly {
            let exists := 0
            let n := mload(a)
            for { let i := 0 } lt(i, n) { i := add(i, 1) } {
                let o := add(add(a, 0x20), shl(5, i))
                if eq(mload(o), x) {
                    exists := 1
                    break
                }
            }
            if iszero(exists) {
                n := add(n, 1)
                mstore(add(a, shl(5, n)), x)
                mstore(a, n)
            }
        }
    }

    function _removeFromArray(uint256[] memory a, uint256 x) internal pure {
        /// @solidity memory-safe-assembly
        assembly {
            let n := mload(a)
            for { let i := 0 } lt(i, n) { i := add(i, 1) } {
                let o := add(add(a, 0x20), shl(5, i))
                if eq(mload(o), x) {
                    mstore(o, mload(add(a, shl(5, n))))
                    mstore(a, sub(n, 1))
                    break
                }
            }
        }
    }

    function testEnumerableAddressSetUpdate() public {
        uint256 cap = 3;
        assertTrue(this.updateAddressSet(address(0), true, cap));
        assertTrue(this.updateAddressSet(address(1), true, cap));
        assertTrue(this.updateAddressSet(address(2), true, cap));
        assertFalse(this.updateAddressSet(address(2), true, cap));

        vm.expectRevert(EnumerableSetLib.ExceedsCapacity.selector);
        this.updateAddressSet(address(3), true, cap);

        assertFalse(this.updateAddressSet(address(3), false, cap));
        assertTrue(this.updateAddressSet(address(2), false, cap));
        assertFalse(this.updateAddressSet(address(2), false, cap));
        assertTrue(this.updateAddressSet(address(3), true, cap));
    }

    function testEnumerableBytes32SetUpdate(bytes32) public {
        uint256 cap = 3;
        assertTrue(this.updateBytes32Set(bytes32("0"), true, cap));
        assertTrue(this.updateBytes32Set(bytes32("1"), true, cap));
        assertTrue(this.updateBytes32Set(bytes32("2"), true, cap));
        assertFalse(this.updateBytes32Set(bytes32("2"), true, cap));

        vm.expectRevert(EnumerableSetLib.ExceedsCapacity.selector);
        this.updateBytes32Set(bytes32("3"), true, cap);

        assertFalse(this.updateBytes32Set(bytes32("3"), false, cap));
        assertTrue(this.updateBytes32Set(bytes32("2"), false, cap));
        assertFalse(this.updateBytes32Set(bytes32("2"), false, cap));
        assertTrue(this.updateBytes32Set(bytes32("3"), true, cap));
    }

    function testEnumerableUint8SetUpdate(bytes32) public {
        uint256 cap = 3;
        assertTrue(this.updateUint8Set(0, true, cap));
        assertTrue(this.updateUint8Set(1, true, cap));
        assertTrue(this.updateUint8Set(2, true, cap));
        assertFalse(this.updateUint8Set(2, true, cap));

        vm.expectRevert(EnumerableSetLib.ExceedsCapacity.selector);
        this.updateUint8Set(3, true, cap);

        assertFalse(this.updateUint8Set(3, false, cap));
        assertTrue(this.updateUint8Set(2, false, cap));
        assertFalse(this.updateUint8Set(2, false, cap));
        assertTrue(this.updateUint8Set(3, true, cap));
    }

    function updateAddressSet(address value, bool isAdd, uint256 cap) public returns (bool) {
        return addressSet.update(value, isAdd, cap);
    }

    function updateBytes32Set(bytes32 value, bool isAdd, uint256 cap) public returns (bool) {
        return bytes32Set.update(value, isAdd, cap);
    }

    function updateUint8Set(uint8 value, bool isAdd, uint256 cap) public returns (bool) {
        return uint8Set.update(value, isAdd, cap);
    }

    function testAddressSetIndexOf(bytes32 r) public {
        LibPRNG.PRNG memory prng;
        prng.state = uint256(r);
        address[] memory a = new address[](_bound(_random(), 0, 16));

        for (uint256 i; i != a.length; ++i) {
            address value = address(uint160(prng.next()));
            addressSet.add(value);
            a[i] = value;
        }

        if (a.length != 0) {
            uint256 i = _random() % a.length;
            address value = a[i];
            assertEq(addressSet.indexOf(value), i);
            assertEq(addressSet.at(addressSet.indexOf(value)), value);
            if (_randomChance(2)) {
                value = address(bytes20(keccak256(abi.encode(value, value, "abcdef"))));
                assertEq(addressSet.indexOf(value), EnumerableSetLib.NOT_FOUND);
            }
        }
    }

    function testBytes32SetIndexOf(bytes32 r) public {
        LibPRNG.PRNG memory prng;
        prng.state = uint256(r);
        bytes32[] memory a = new bytes32[](_bound(_random(), 0, 16));

        for (uint256 i; i != a.length; ++i) {
            bytes32 value = bytes32(prng.next());
            bytes32Set.add(value);
            a[i] = value;
        }

        if (a.length != 0) {
            uint256 i = _random() % a.length;
            bytes32 value = a[i];
            assertEq(bytes32Set.indexOf(value), i);
            assertEq(bytes32Set.at(bytes32Set.indexOf(value)), value);
            if (_randomChance(2)) {
                value = keccak256(abi.encode(value, value, "abcdef"));
                assertEq(bytes32Set.indexOf(value), EnumerableSetLib.NOT_FOUND);
            }
        }
    }

    function testEnumerableUint8SetIndexOf(uint256 flags, uint8 value) public {
        uint8[] memory ordinals = _flagsToOrdinals(flags);
        unchecked {
            for (uint256 i; i != ordinals.length; ++i) {
                uint8Set.add(ordinals[i]);
            }
            if (uint8Set.contains(value)) {
                assertEq(uint8Set.at(uint8Set.indexOf(value)), value);
            } else {
                assertEq(uint8Set.indexOf(value), EnumerableSetLib.NOT_FOUND);
            }
        }
    }
}

