            assertEq(a, aCopy);
        }
    }

    function testSort(uint256) public {
        unchecked {
            uint256[] memory a = _randomUints(_randomArrayLength());
            LibSort.sort(a);
            assertTrue(_isSorted(a));
        }
    }

    function testSortBasicCase() public {
