    function testPermit2AnythingWithNonContractReverts() public {
        _TestTemps memory t;
        t.token = _randomHashedAddress();
        t.deadline = block.timestamp;
        (t.signer, t.privateKey) = _randomSigner();
        t.spender = _randomNonZeroAddress();
