        vm.prank(t.signer);
        erc20.approve(_PERMIT2, type(uint256).max);

        t.permit.details.token = address(erc20);
        t.permit.details.amount = t.amount;
        t.permit.details.expiration = type(uint48).max;
        (,, t.permit.details.nonce) =
            IPermit2(_PERMIT2).allowance(t.signer, address(erc20), t.spender);
        t.permit.spender = t.spender;
        t.permit.sigDeadline = t.deadline;

        _generatePermitSignatureRaw(t);
        vm.expectRevert(SafeTransferLib.Permit2AmountOverflow.selector);
        this.simplePermit2(t);
    }

    function testPermit2ApproveAndLockdown(bytes32) public {
        _TestTemps memory t;
        t.token = _randomHashedAddress();
        t.spender = _randomHashedAddress();
        t.amount = _bound(_random(), 0, type(uint160).max);
        (t.retrievedAmount, t.retrievedExpiration,) =
            IPermit2(_PERMIT2).allowance(address(this), t.token, t.spender);
        assertEq(t.retrievedAmount, 0);
        assertEq(t.retrievedExpiration, 0);

        t.expiration = uint48(_bound(t.expiration, block.timestamp, type(uint48).max));

        SafeTransferLib.permit2Approve(t.token, t.spender, uint160(t.amount), t.expiration);

        (t.retrievedAmount, t.retrievedExpiration,) =
            IPermit2(_PERMIT2).allowance(address(this), t.token, t.spender);
        assertEq(t.retrievedAmount, t.amount);
        assertEq(t.retrievedExpiration, t.expiration);

        SafeTransferLib.permit2Lockdown(t.token, t.spender);

        (t.retrievedAmount, t.retrievedExpiration,) =
            IPermit2(_PERMIT2).allowance(address(this), t.token, t.spender);
        assertEq(t.retrievedAmount, 0);
        assertEq(t.retrievedExpiration, t.expiration); // Expiration stays the same.
    }

    function _generatePermitSignatureRaw(_TestTemps memory t) internal view {
        bytes32 domainSeparator = ERC20(_PERMIT2).DOMAIN_SEPARATOR();
        t.hash = keccak256(abi.encode(_PERMIT_DETAILS_TYPEHASH, t.permit.details));
        t.hash = keccak256(
            abi.encode(_PERMIT_SINGLE_TYPEHASH, t.hash, t.permit.spender, t.permit.sigDeadline)
        );
        t.hash = keccak256(abi.encodePacked("\x19\x01", domainSeparator, t.hash));
        (t.v, t.r, t.s) = vm.sign(t.privateKey, t.hash);
    }

    function permit2TransferFrom(address token, address from, address to, uint256 amount) public {
        SafeTransferLib.permit2TransferFrom(
            _brutalized(token), _brutalized(from), _brutalized(to), amount
        );
    }

    function safeTransferFrom2(address token, address from, address to, uint256 amount) public {
        SafeTransferLib.safeTransferFrom2(
            _brutalized(token), _brutalized(from), _brutalized(to), amount
        );
    }

    function permit2(_TestTemps calldata t) public {
        SafeTransferLib.permit2(
            _brutalized(t.token),
            _brutalized(t.signer),
            _brutalized(t.spender),
            t.amount,
            t.deadline,
            t.v,
            t.r,
            t.s
        );
    }

    function simplePermit2(_TestTemps calldata t) public {
        SafeTransferLib.simplePermit2(
            _brutalized(t.token),
            _brutalized(t.signer),
            _brutalized(t.spender),
            t.amount,
            t.deadline,
            t.v,
            t.r,
            t.s
        );
    }

    function testTotalSupplyQuery() public {
        uint256 totalSupplyBefore = this.totalSupplyQuery(address(erc20));
        erc20.burn(address(this), 123);
        assertEq(this.totalSupplyQuery(address(erc20)), totalSupplyBefore - 123);
        vm.expectRevert(SafeTransferLib.TotalSupplyQueryFailed.selector);
        this.totalSupplyQuery(address(0));
    }

    function totalSupplyQuery(address token) public view returns (uint256) {
        return SafeTransferLib.totalSupply(token);
    }

    function testSaveMoveETHViaVault(bytes32) public {
        address to = _randomUniqueHashedAddress();
        assertEq(to.balance, 0);

        uint256 amount0 = _bound(_random(), 0, 2 ** 128 - 1);
        uint256 amount1 = _bound(_random(), 0, 2 ** 128 - 1);
        vm.deal(address(this), 2 ** 160 - 1);
        address vault = this.safeMoveETH(to, amount0);
        assertEq(vault.balance, amount0);
        assertEq(this.safeMoveETH(to, amount1), vault);
        assertEq(vault.balance, amount0 + amount1);

        address pranker = _randomUniqueHashedAddress();
        vm.prank(pranker);
        (bool success,) = vault.call("");
        require(success);
        assertEq(vault.balance, amount0 + amount1);
        assertEq(to.balance, 0);

        vm.prank(to);
        (success,) = vault.call("");
        require(success);
        assertEq(vault.balance, 0);
        assertEq(to.balance, amount0 + amount1);
    }

    function testSafeMoveETHViaMover(bytes32) public {
        _deployETHMover();

        address to = _randomHashedAddress();
        assertEq(to.balance, 0);

        uint256 amount0 = _bound(_random(), 0, 2 ** 128 - 1);
        uint256 amount1 = _bound(_random(), 0, 2 ** 128 - 1);
        vm.deal(address(this), 2 ** 160 - 1);
        uint256 selfBalanceBefore = address(this).balance;
        assertEq(SafeTransferLib.safeMoveETH(to, amount0), address(0));

        assertEq(to.balance, amount0);
        assertEq(address(this).balance, selfBalanceBefore - amount0);

        if (_randomChance(2)) {
            vm.etch(SafeTransferLib.ETH_MOVER, "");
        }

        if (SafeTransferLib.ETH_MOVER.code.length == 0) {
            address vault = this.safeMoveETH(to, amount1);
            assertEq(vault.balance, amount1);
            assertEq(to.balance, amount0);
            assertEq(address(this).balance, selfBalanceBefore - amount0 - amount1);
        } else {
            assertEq(this.safeMoveETH(to, amount1), address(0));
            assertEq(to.balance, amount0 + amount1);
            assertEq(address(this).balance, selfBalanceBefore - amount0 - amount1);
        }
    }

    function testSaveMoveETHToSelfIsNoOp(bytes32) public {
        if (_randomChance(2)) _deployETHMover();
        address to = address(this);
        uint256 amount = _bound(_random(), 0, 2 ** 128 - 1);
        vm.deal(address(this), 2 ** 160 - 1);
        uint256 selfBalanceBefore = address(this).balance;
        assertEq(this.safeMoveETH(to, amount), address(0));
        assertEq(address(this).balance, selfBalanceBefore);
    }

    function testSaveMoveETHToMoverReverts(bytes32) public {
        if (_randomChance(2)) _deployETHMover();
        address to = SafeTransferLib.ETH_MOVER;

        uint256 amount = _bound(_random(), 0, 2 ** 128 - 1);
        vm.deal(address(this), 2 ** 160 - 1);

        vm.expectRevert(SafeTransferLib.ETHTransferFailed.selector);
        this.safeMoveETH(to, amount);
    }

    function testSaveMoveETHInsufficientBalanceReverts(bytes32) public {
        if (_randomChance(2)) _deployETHMover();
        address to = _randomHashedAddress();

        uint256 amount = _bound(_random(), 0, 2 ** 128 - 1);
        vm.deal(address(this), 2 ** 128 - 1);

        if (address(this).balance < amount) {
            vm.expectRevert(SafeTransferLib.ETHTransferFailed.selector);
            this.safeMoveETH(to, amount);
        } else {
            this.safeMoveETH(to, amount);
        }
    }

    function safeMoveETH(address to, uint256 amount) public returns (address) {
        if (_randomChance(2)) _misalignFreeMemoryPointer();
        if (_randomChance(2)) _brutalizeMemory();
        return SafeTransferLib.safeMoveETH(_brutalized(to), amount);
    }

    function _deployETHMover() internal {
        bytes memory initCode = hex"623d35ff3d526003601df3";
        bytes32 salt = 0x000000000000000000000000000000000000000063d76c4f57ebf10084429e18;
        address mover = _nicksCreate2(0, salt, initCode);
        assertEq(mover.code, hex"3d35ff");
        assertEq(mover, SafeTransferLib.ETH_MOVER);
    }
}

